import pytest
from cachetools import TTLCache

@pytest.mark.benchmark(group="cache_ttl")
def test_cache_eager_expiration(benchmark):
    cache = TTLCache(maxsize=10000, ttl=1)

    def setup():
        for i in range(10000):
            cache[i] = f"value_{i}"

    def operation():
        cache.get(1)

    benchmark.pedantic(operation, setup=setup, rounds=100, iterations=10)

    # Vérification de l'éviction eager
    assert 1 not in cache

